'use client'

import { useEffect, useRef } from 'react'
import { gsap } from 'gsap'
import { ScrollTrigger } from 'gsap/ScrollTrigger'

gsap.registerPlugin(ScrollTrigger)

const principles = [
  {
    number: '01',
    title: 'Integration Over Addition',
    text: 'We do not decorate spaces; we design systems where storage, structure, and surface exist as one. Minimalism achieved through thoughtful integration, not austere elimination.',
  },
  {
    number: '02',
    title: 'Material Honesty',
    text: 'Wood remains wood. Stone remains stone. We select materials for their inherent qualities and allow them to express their true nature, weathering time with grace.',
  },
  {
    number: '03',
    title: 'Functional Restraint',
    text: 'Every element must earn its place. If it serves no purpose, it serves no place in our designs. This discipline creates spaces of remarkable clarity.',
  },
  {
    number: '04',
    title: 'Timeless Duration',
    text: 'We design for decades, not seasons. Our work resists trends in favor of permanence, creating environments that improve with age and use.',
  },
]

export default function PhilosophySection() {
  const titleRef = useRef<HTMLHeadingElement>(null)
  const cardsRef = useRef<(HTMLDivElement | null)[]>([])

  useEffect(() => {
    gsap.fromTo(
      titleRef.current,
      { opacity: 0, y: 30 },
      {
        opacity: 1,
        y: 0,
        duration: 1,
        scrollTrigger: {
          trigger: titleRef.current,
          start: 'top 80%',
        }
      }
    )

    cardsRef.current.forEach((card, index) => {
      gsap.fromTo(
        card,
        { opacity: 0, y: 50 },
        {
          opacity: 1,
          y: 0,
          duration: 1,
          scrollTrigger: {
            trigger: card,
            start: 'top 85%',
          }
        }
      )
    })
  }, [])

  return (
    <section className="py-32 px-8 bg-preto text-branco">
      <div className="max-w-[1400px] mx-auto">
        {/* Header */}
        <div className="text-center mb-20">
          <h2 
            ref={titleRef}
            className="font-display text-branco font-medium mb-6"
            style={{ fontSize: 'clamp(2.5rem, 5vw, 5rem)' }}
          >
            Our Philosophy
          </h2>
          <p className="text-inox text-lg font-light">
            The principles that guide every design decision
          </p>
        </div>

        {/* Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
          {principles.map((principle, index) => (
            <div
              key={principle.number}
              ref={(el) => { cardsRef.current[index] = el }}
              className="p-12 border border-cinza/30 hover:border-branco transition-all duration-400 hover:-translate-y-3 group"
            >
              <div className="font-display text-cinza text-5xl mb-6 group-hover:text-branco transition-colors">
                {principle.number}
              </div>
              <h3 className="font-display text-branco text-3xl mb-6">
                {principle.title}
              </h3>
              <p className="text-inox text-lg leading-relaxed font-light">
                {principle.text}
              </p>
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}