'use client'

import { useEffect, useRef } from 'react'
import { gsap } from 'gsap'
import { ScrollTrigger } from 'gsap/ScrollTrigger'

gsap.registerPlugin(ScrollTrigger)

const collections = [
  {
    name: 'Essence',
    description: 'Functional minimalism distilled to its purest form. Every piece serves a purpose, nothing more, nothing less.',
  },
  {
    name: 'Permanence',
    description: 'Timeless structures designed to improve with age. Built for decades, not seasons.',
  },
  {
    name: 'Integration',
    description: 'Seamless living where storage, structure, and surface exist as one cohesive system.',
  },
]

export default function CollectionsGrid() {
  const sectionRef = useRef<HTMLElement>(null)
  const titleRef = useRef<HTMLHeadingElement>(null)
  const cardsRef = useRef<(HTMLDivElement | null)[]>([])

  useEffect(() => {
    gsap.fromTo(
      titleRef.current,
      { opacity: 0, y: 30 },
      {
        opacity: 1,
        y: 0,
        duration: 1,
        scrollTrigger: {
          trigger: titleRef.current,
          start: 'top 80%',
        }
      }
    )

    cardsRef.current.forEach((card, index) => {
      gsap.fromTo(
        card,
        { opacity: 0, y: 80 },
        {
          opacity: 1,
          y: 0,
          duration: 1,
          delay: index * 0.2,
          scrollTrigger: {
            trigger: card,
            start: 'top 85%',
          }
        }
      )
    })
  }, [])

  return (
    <section ref={sectionRef} id="collections" className="py-32 px-8 bg-branco">
      <div className="max-w-[1400px] mx-auto">
        {/* Header */}
        <div className="text-center mb-20">
          <h2 
            ref={titleRef}
            className="font-display text-preto font-medium mb-6"
            style={{ fontSize: 'clamp(2.5rem, 5vw, 5rem)' }}
          >
            Our Collections
          </h2>
          <p className="text-cinza text-lg font-light">
            Explore our carefully curated furniture and interior designs
          </p>
        </div>

        {/* Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {collections.map((collection, index) => (
            <div
              key={collection.name}
              ref={(el) => { cardsRef.current[index] = el }}
              className="group relative h-[600px] bg-inox overflow-hidden cursor-pointer"
            >
              {/* Overlay that appears on hover */}
              <div className="absolute inset-0 bg-gradient-to-t from-preto/90 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500 z-10" />
              
              {/* Content */}
              <div className="absolute bottom-0 left-0 right-0 p-12 z-20 translate-y-5 opacity-0 group-hover:translate-y-0 group-hover:opacity-100 transition-all duration-500">
                <h3 className="font-display text-branco text-4xl mb-4">
                  {collection.name}
                </h3>
                <p className="text-inox text-base leading-relaxed mb-6">
                  {collection.description}
                </p>
                <button className="inline-flex items-center gap-2 text-branco text-sm tracking-wider group/btn">
                  <span>Explore Collection</span>
                  <svg 
                    className="w-5 h-5 transition-transform group-hover/btn:translate-x-2" 
                    fill="none" 
                    stroke="currentColor" 
                    viewBox="0 0 24 24"
                  >
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 8l4 4m0 0l-4 4m4-4H3" />
                  </svg>
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}