'use client'

import { useEffect, useRef } from 'react'
import { gsap } from 'gsap'

export default function Hero() {
  const titleRef = useRef<HTMLHeadingElement>(null)
  const subtitleRef = useRef<HTMLParagraphElement>(null)
  const scrollRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    const tl = gsap.timeline({ defaults: { ease: 'power3.out' } })
    
    tl.fromTo(
      titleRef.current,
      { opacity: 0, y: 50 },
      { opacity: 1, y: 0, duration: 1.2, delay: 0.3 }
    )
    .fromTo(
      subtitleRef.current,
      { opacity: 0, y: 30 },
      { opacity: 1, y: 0, duration: 1 },
      '-=0.6'
    )
    .fromTo(
      scrollRef.current,
      { opacity: 0 },
      { opacity: 1, duration: 1 },
      '-=0.4'
    )
  }, [])

  return (
    <section className="relative h-screen flex items-center justify-center bg-branco overflow-hidden">
      <div className="text-center px-8 max-w-[1400px]">
        <h1 
          ref={titleRef}
          className="font-display text-preto font-medium leading-none mb-8 whitespace-nowrap"
          style={{ 
            fontSize: 'clamp(2.5rem, 8vw, 7rem)',
            letterSpacing: '-0.02em'
          }}
        >
          BABEL DESIGNS
        </h1>
        <p 
          ref={subtitleRef}
          className="text-cinza tracking-[0.3em] uppercase font-light"
          style={{ fontSize: 'clamp(0.9rem, 2vw, 1.5rem)' }}
        >
          Crafted for all, Owned by few
        </p>
      </div>

      {/* Scroll Indicator */}
      <div 
        ref={scrollRef}
        className="absolute bottom-12 left-1/2 -translate-x-1/2 flex flex-col items-center gap-2"
      >
        <span className="text-cinza text-xs tracking-[0.2em] uppercase">Scroll</span>
        <svg 
          className="w-6 h-6 text-cinza animate-bounce" 
          fill="none" 
          stroke="currentColor" 
          viewBox="0 0 24 24"
        >
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19 14l-7 7m0 0l-7-7m7 7V3" />
        </svg>
      </div>
    </section>
  )
}